import 'package:flutter/material.dart'; class GestureRecognizerOverlay extends StatelessWidget { final void Function(double, double) onTap; final void Function(double, double, double, double) onSwipe; const GestureRecognizerOverlay({super.key, required this.onTap, required this.onSwipe}); @override Widget build(BuildContext context) { Offset? swipeStart; return GestureDetector(onTapUp: (d) => onTap(d.localPosition.dx, d.localPosition.dy), onPanStart: (d) => swipeStart = d.localPosition, onPanEnd: (d) { if (swipeStart != null) onSwipe(swipeStart!.dx, swipeStart!.dy, d.velocity.pixelsPerSecond.dx, d.velocity.pixelsPerSecond.dy); }, child: Container(color: Colors.transparent, width: double.infinity, height: double.infinity)); } }